<?php require_once '../config/db.php'; require_once '../includes/auth.php'; require_admin(); $page_title='Trainers';
if(isset($_GET['delete'])){ $id=intval($_GET['delete']); mysqli_query($conn,"DELETE FROM PERSON WHERE person_id=$id"); header('Location: trainers.php'); exit(); }
if($_SERVER['REQUEST_METHOD']==='POST'){ mysqli_begin_transaction($conn); try{ $stmt=mysqli_prepare($conn,'INSERT INTO PERSON(first_name,last_name,date_of_birth,gender,street,city,email) VALUES(?,?,?,?,?,?,?)'); mysqli_stmt_bind_param($stmt,'sssssss',$_POST['first_name'],$_POST['last_name'],$_POST['date_of_birth'],$_POST['gender'],$_POST['street'],$_POST['city'],$_POST['email']); mysqli_stmt_execute($stmt); $pid=mysqli_insert_id($conn); $stmt=mysqli_prepare($conn,'INSERT INTO TRAINER(person_id,specialization_area,experience_years,salary,trainer_status) VALUES(?,?,?,?,?)'); mysqli_stmt_bind_param($stmt,'isids',$pid,$_POST['specialization_area'],$_POST['experience_years'],$_POST['salary'],$_POST['trainer_status']); mysqli_stmt_execute($stmt); mysqli_commit($conn);}catch(Exception $e){mysqli_rollback($conn);} header('Location: trainers.php'); exit(); }
$result=mysqli_query($conn,"SELECT t.person_id, CONCAT(p.first_name,' ',p.last_name) trainer_name, p.email, t.specialization_area, t.experience_years, t.salary, t.trainer_status FROM TRAINER t JOIN PERSON p ON t.person_id=p.person_id ORDER BY t.person_id DESC"); require_once '../includes/header.php'; require_once '../includes/sidebar.php'; ?>
<div class="card form-card"><h2>Add Trainer</h2><form method="POST" class="form-grid"><div><label>First Name</label><input class="input" name="first_name" required></div><div><label>Last Name</label><input class="input" name="last_name" required></div><div><label>DOB</label><input class="input" type="date" name="date_of_birth" required></div><div><label>Gender</label><select name="gender"><option>Male</option><option>Female</option><option>Other</option></select></div><div><label>Street</label><input class="input" name="street" required></div><div><label>City</label><input class="input" name="city" required></div><div><label>Email</label><input class="input" type="email" name="email" required></div><div><label>Specialization</label><input class="input" name="specialization_area" required></div><div><label>Experience</label><input class="input" type="number" name="experience_years" required></div><div><label>Salary</label><input class="input" type="number" step="0.01" name="salary" required></div><div><label>Status</label><select name="trainer_status"><option>Active</option><option>Inactive</option><option>On Leave</option></select></div><div class="full"><button class="btn">Add Trainer</button></div></form></div><h2 class="section-title">Trainer Records</h2><div class="table-wrap"><table><tr><th>ID</th><th>Name</th><th>Email</th><th>Specialization</th><th>Experience</th><th>Salary</th><th>Status</th><th>Action</th></tr><?php while($r=mysqli_fetch_assoc($result)): ?><tr><td><?= safe($r['person_id']) ?></td><td><?= safe($r['trainer_name']) ?></td><td><?= safe($r['email']) ?></td><td><?= safe($r['specialization_area']) ?></td><td><?= safe($r['experience_years']) ?></td><td><?= safe($r['salary']) ?></td><td><span class="badge"><?= safe($r['trainer_status']) ?></span></td><td><a class="btn btn-danger" onclick="return confirm('Delete trainer?')" href="trainers.php?delete=<?= $r['person_id'] ?>">Delete</a></td></tr><?php endwhile; ?></table></div><?php require_once '../includes/footer.php'; ?>
